    .unwrap();

    match normalized {
        Expr::BinaryExpr(BinaryExpr { right, .. }) => match right.as_ref() {
            Expr::Literal(value, _) => {
                assert_eq!(value, &ScalarValue::Decimal128(Some(1505), 6, 1));
