            .update_datafusion_session(&ctx2.state())
            .unwrap();
        ctx2.register_table(
            "test",
            table_for_query.table_provider().await.unwrap(),
        )
        .unwrap();

        let rows_after_second = ctx2
            .sql("SELECT COUNT(*) as cnt FROM test")
            .await
            .unwrap()
            .collect()
            .await
            .unwrap();
        let cnt2: i64 = rows_after_second[0]
            .column_by_name("cnt")
            .unwrap()
            .as_any()
            .downcast_ref::<arrow::array::Int64Array>()
            .unwrap()
            .value(0);

        assert_eq!(
            cnt2, 3,
            "Expected 3 rows after second merge, but got {cnt2} (partition value with spaces)"
        );

        // After matching updates, the original files should have been removed
        assert!(
            metrics2.num_target_files_removed >= 1,
            "Expected old files to be removed when merge updates rows in partition with spaces, got {}",
            metrics2.num_target_files_removed
        );
    }
}

