    #[tokio::test]
    async fn test_merge_idempotent_with_partition_value_containing_spaces() {
        let table_schema = StructType::try_new(vec![
            StructField::new(
                "region".to_string(),
                DeltaDataType::Primitive(PrimitiveType::String),
                true,
            ),
            StructField::new(
                "group".to_string(),
                DeltaDataType::Primitive(PrimitiveType::String),
                true,
            ),
            StructField::new(
                "val".to_string(),
                DeltaDataType::Primitive(PrimitiveType::Double),
                true,
            ),
        ])
        .unwrap();

        let table = DeltaTable::new_in_memory()
            .create()
            .with_columns(table_schema.fields().cloned())
            .with_partition_columns(vec!["group".to_string()])
            .await
            .unwrap();

        let arrow_schema = Arc::new(ArrowSchema::new(vec![
            Field::new("region", ArrowDataType::Utf8, true),
            Field::new("group", ArrowDataType::Utf8, true),
            Field::new("val", ArrowDataType::Float64, true),
        ]));

        let source_batch = RecordBatch::try_new(
            Arc::clone(&arrow_schema),
            vec![
                Arc::new(arrow::array::StringArray::from(vec!["A", "B", "C"])),
                Arc::new(arrow::array::StringArray::from(vec![
                    "foo bar",
                    "foo bar",
                    "foo bar",
                ])),
                Arc::new(arrow::array::Float64Array::from(vec![1.0, 2.0, 3.0])),
            ],
        )
        .unwrap();

        let ctx = SessionContext::new();
        let source = ctx.read_batch(source_batch).unwrap();

        // Perform two identical merges. The second should be a no-op
        // (no files removed, no new rows, no new files added) and the
        // row count should remain 3.
        let (table, _metrics) = table
            .merge(
                source.clone(),
                col("target.group").eq(col("source.group"))
                    .and(col("target.region").eq(col("source.region"))),
            )
            .with_source_alias("source")
            .with_target_alias("target")
            .when_matched_update_all()
            .when_not_matched_insert_all()
            .await
            .unwrap();

        let table_for_query =
            DeltaTable::new_with_state(table.log_store.clone(), table.snapshot().unwrap().clone());
        table_for_query
            .update_datafusion_session(&ctx.state())
            .unwrap();
        ctx.register_table(
            "test",
            table_for_query.table_provider().await.unwrap(),
        )
        .unwrap();

        let rows_after_first = ctx
            .sql("SELECT COUNT(*) as cnt FROM test")
            .await
            .unwrap()
            .collect()
            .await
            .unwrap();
        assert_eq!(rows_after_first[0].num_rows(), 1);
        let cnt: i64 = rows_after_first[0]
            .column_by_name("cnt")
            .unwrap()
            .as_any()
            .downcast_ref::<arrow::array::Int64Array>()
            .unwrap()
            .value(0);
        assert_eq!(cnt, 3, "Expected 3 rows after first merge");

        // Second identical merge
        let (table, metrics2) = table
            .merge(
                source.clone(),
                col("target.group").eq(col("source.group"))
                    .and(col("target.region").eq(col("source.region"))),
            )
            .with_source_alias("source")
            .with_target_alias("target")
            .when_matched_update_all()
            .when_not_matched_insert_all()
            .await
            .unwrap();

        let table_for_query =
            DeltaTable::new_with_state(table.log_store.clone(), table.snapshot().unwrap().clone());
        let ctx2 = SessionContext::new();
        table_for_query
            .update_datafusion_session(&ctx2.state())
            .unwrap();
        ctx2.register_table(
            "test",
            table_for_query.table_provider().await.unwrap(),
        )
        .unwrap();

        let rows_after_second = ctx2
            .sql("SELECT COUNT(*) as cnt FROM test")
            .await
            .unwrap()
            .collect()
            .await
            .unwrap();
        let cnt2: i64 = rows_after_second[0]
            .column_by_name("cnt")
            .unwrap()
            .as_any()
            .downcast_ref::<arrow::array::Int64Array>()
            .unwrap()
            .value(0);

        assert_eq!(
            cnt2, 3,
            "Expected 3 rows after second merge, but got {cnt2} (partition value with spaces)"
        );

        // After matching updates, the original files should have been removed
        assert!(
            metrics2.num_target_files_removed >= 1,
            "Expected old files to be removed when merge updates rows in partition with spaces, got {}",
            metrics2.num_target_files_removed
        );
    }
}

